-- 7. 知识库表 (knowledge)
-- 您的表字段: title, content, category, create_time, update_time
-- 删除字段: author, status (您的表中无这些字段)
-- ============================================================
INSERT INTO `knowledge` (`title`, `content`, `category`, `create_time`, `update_time`) VALUES
                                                                                           ('LED路灯常见故障排查指南',
                                                                                            '## LED路灯常见故障排查指南\n\n### 1. 灯具完全不亮\n- **可能原因**: 电源线断开、驱动电源损坏、LED模组烧毁\n- **排查步骤**: \n  1. 检查输入电压是否正常(220V±10%)\n  2. 检查驱动电源输出端电压\n  3. 目测LED模组是否有明显烧毁痕迹\n\n### 2. 灯具闪烁\n- **可能原因**: 驱动电源不稳定、接触不良、电网波动\n- **排查步骤**:\n  1. 检查接线端子是否紧固\n  2. 测量输入电压波动范围\n  3. 更换驱动电源测试\n\n### 3. 亮度不足\n- **可能原因**: LED光衰、散热不良、驱动电流偏低\n- **排查步骤**:\n  1. 测量实际功率与额定功率对比\n  2. 检查散热器是否积灰\n  3. 检测LED模组光衰程度',
                                                                                            '运维手册', '2025-06-10 09:00:00', '2025-06-10 09:00:00'),

                                                                                           ('太阳能路灯维护保养规范',
                                                                                            '## 太阳能路灯维护保养规范\n\n### 日常巡检(每周)\n1. 检查太阳能板表面清洁度\n2. 观察LED灯具工作状态\n3. 记录蓄电池电压\n\n### 月度保养\n1. 清洁太阳能板表面灰尘\n2. 检查支架紧固件\n3. 测试充放电控制器功能\n4. 测量蓄电池容量\n\n### 季度保养\n1. 全面检查线路连接\n2. 测试后备电源\n3. 更新固件(如有)\n4. 记录系统运行数据\n\n### 年度保养\n1. 更换老化蓄电池\n2. 全面检测系统性能\n3. 清洁灯杆及基础检查',
                                                                                            '运维手册', '2025-07-20 14:00:00', '2025-07-20 14:00:00'),
                                                                                           ('智慧路灯系统操作手册',
                                                                                            '## 智慧路灯管理系统操作手册\n\n### 1. 登录系统\n访问系统地址，使用分配的账号密码登录。默认管理员账号: admin\n\n### 2. 路灯监控\n- **实时监控**: 在地图视图查看所有路灯状态\n- **单灯控制**: 点击路灯图标可进行开关/调光操作\n- **批量控制**: 按区域或分组批量操作\n\n### 3. 报警处理\n- 查看报警列表，按级别排序\n- 点击报警查看详情\n- 指派维护人员处理\n- 处理后填写处理记录\n\n### 4. 数据查询\n- 传感器历史数据查询\n- 能耗统计报表\n- 故障率统计',
                                                                                            '系统文档', '2025-08-01 10:00:00', '2025-08-10 16:00:00'),

                                                                                           ('PM2.5传感器校准方法',
                                                                                            '## PM2.5传感器校准方法\n\n### 校准周期\n建议每6个月进行一次校准\n\n### 校准步骤\n1. 准备标准参考仪器(需经过计量认证)\n2. 将传感器与参考仪器放置于相同环境\n3. 采集至少24小时连续数据\n4. 计算偏差系数 = 参考值 / 传感器读数\n5. 将偏差系数写入传感器配置\n\n### 判断标准\n- 偏差 < 5%: 无需校准\n- 偏差 5%-15%: 软件校准\n- 偏差 > 15%: 硬件检查或更换',
                                                                                            '技术规范', '2025-09-15 11:00:00', '2025-09-15 11:00:00'),

                                                                                           ('高压钠灯与LED路灯对比分析',
                                                                                            '## 高压钠灯 vs LED路灯\n\n| 对比维度 | 高压钠灯 | LED路灯 |\n|---------|---------|--------|\n| 功率 | 250W-400W | 100W-200W |\n| 光效 | 80-120 lm/W | 120-160 lm/W |\n| 寿命 | 8000-12000h | 50000-100000h |\n| 显色指数 | 20-30 | 70-90 |\n| 启动时间 | 5-10分钟 | 瞬时 |\n| 年能耗(12h/天) | 1095 kWh | 438 kWh |\n| 维护成本 | 高(需定期更换灯泡) | 低 |\n\n### 建议\n新建项目推荐全部使用LED路灯，既有高压钠灯项目建议分批次替换，投资回收期约2-3年。',
                                                                                            '技术文档', '2025-10-01 09:00:00', '2025-10-01 09:00:00'),

                                                                                           ('系统应急预案',
                                                                                            '## 智慧路灯系统应急预案\n\n### 大规模断电故障\n1. 启动UPS备用电源\n2. 通知电力部门排查\n3. 重要路段启动应急照明\n4. 通过系统群发通知\n\n### 系统遭受网络攻击\n1. 立即切断外网连接\n2. 切换至本地手动控制模式\n3. 通知信息安全部门\n4. 保留攻击日志证据\n\n### 极端天气应对(台风/暴雨)\n1. 提前降低路灯高度(可升降式)\n2. 加固灯杆基础\n3. 关闭非必要路灯\n4. 检查防水密封\n\n### 数据丢失恢复\n1. 从每日备份恢复数据\n2. 检查数据完整性\n3. 重新同步传感器数据\n4. 生成丢失时段报表',
                                                                                            '应急方案', '2025-11-15 15:00:00', '2025-11-15 15:00:00');

